#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=; package=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; --package) package="${2:?}"; shift 2;; *) archphene_die "unknown argument: $1";; esac; done; [[ -n "$serial" ]] || archphene_die '--serial is required'; archphene_init_adb "$serial"; activity="$(archphene_adb_run shell cmd package resolve-activity --brief -a android.intent.action.MAIN -c android.intent.category.LAUNCHER "$package" | tail -n1 | tr -d '\r')"; [[ "$activity" == */* ]] || archphene_die "could not resolve activity"
child(){ local parent="$1"; archphene_adb_run shell ps -A -o PID,PPID,NAME | awk -v p="$parent" '$2==p && ($3=="loader" || $3=="libarchphene_ld.so"){print $1;exit}'; }; bounds(){ local ui; ui="$(archphene_capture_ui "$1")"; python3 -c 'import re,sys;m=re.search(r"class=\"android\.widget\.ImageView\"[^>]*bounds=\"(\[[0-9]+,[0-9]+\]\[[0-9]+,[0-9]+\])\"",sys.stdin.read());print(m.group(1) if m else "")' <<<"$ui"; }
archphene_adb_run shell pm clear "$package" >/dev/null; archphene_adb_run shell am start -W --windowingMode 5 -n "$activity" >/dev/null; sleep 8; pid="$(archphene_adb_run shell pidof "$package" | tr -d '\r')"; original="$(child "$pid")"; activities="$(archphene_adb_run shell dumpsys activity activities)"; task="$(python3 -c 'import re,sys;p=sys.argv[1];m=re.search(r"Task\{[^\r\n]*#(\d+)[^\r\n]*"+re.escape(p)+r"[^\r\n]*mode=freeform",sys.stdin.read());print(m.group(1) if m else "")' "$package" <<<"$activities")"; [[ -n "$pid" && -n "$original" && -n "$task" ]] || archphene_die "could not identify freeform KCalc app=$pid child=$original task=$task"; trap 'archphene_adb_run shell am force-stop "$package" >/dev/null 2>&1 || true' EXIT
archphene_adb_run shell am task resize "$task" 80 180 920 1500; sleep 4; small_child="$(child "$pid")"; small="$(bounds kcalc-freeform-small)"; archphene_adb_run shell am task resize "$task" 0 0 1026 2200; sleep 4; restored_child="$(child "$pid")"; restored="$(bounds kcalc-freeform-restored)"; [[ "$original" == "$small_child" && "$original" == "$restored_child" ]] || archphene_die 'Linux child restarted during resize'; [[ -n "$small" && "$small" != "$restored" ]] || archphene_die "viewport did not change: $small"; archphene_note "KCalc physical freeform resize passed on $serial: PID $original, $small -> $restored."
